CustomFunction.Calculation:
// Executes SELECT MAX(column) for the assembled query and returns the maximum value.
// column accepts Table::Field references, GetFieldName() strings, or SQL expressions.
// The original query object is not modified.
// Returns "" on error or empty result.
Let
(
[
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_q = JSONSetElement ( query ; "selects" ; "MAX(" & _column & ")" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetValue ( _result ; 1 )
)
